arguments.new_str:
using System.ComponentModel;
using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public class MyControl : UserControl
{
    private readonly StatusStrip _statusStrip;

    public MyControl()
    {
        _statusStrip = new StatusStrip();
        // .NET 9: StatusStrip no longer defaults to System rendering.
        // Set it explicitly to preserve the previous appearance.
        _statusStrip.RenderMode = ToolStripRenderMode.System;
        Controls.Add(_statusStrip);
    }

    [Editor(typeof(SafeDropDownEditor), typeof(UITypeEditor))]
    public string DisplayName { get; set; }

    public int MaxItems { get; set; }
}

/// <summary>
/// .NET 9: IWindowsFormsEditorService.DropDownControl now throws
/// ArgumentNullException when passed null. Guard against it.
/// </summary>
public class SafeDropDownEditor : UITypeEditor
{
    public override UITypeEditorEditStyle GetEditStyle(ITypeDescriptorContext context)
        => UITypeEditorEditStyle.DropDown;

    public override object EditValue(
        ITypeDescriptorContext context, IServiceProvider provider, object value)
    {
        var editorService = provider?.GetService(typeof(IWindowsFormsEditorService))
            as IWindowsFormsEditorService;
        if (editorService == null) return value;

        var control = CreateDropDownControl(value);
        if (control is not null)
        {
            editorService.DropDownControl(control);
            value = control.Text;
        }
        return value;
    }

    private static Control? CreateDropDownControl(object value)
    {
        // May return null in some cases – caller must guard before
        // passing to DropDownControl, which rejects null in .NET 9.
        if (value is not string s) return null;
        return new TextBox { Text = s };
    }
}

